@layer mergora.components {
  .mrg-chart {
    display: grid;
    gap: var(--mrg-semantic-space-stack-md);
    margin: 0;
    padding: var(--mrg-semantic-density-panel-padding);
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-strong);
    border-radius: var(--mrg-semantic-radius-panel);
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-canvas);
    font-family: var(--mrg-semantic-font-family-prose);
  }
  .mrg-chart figcaption {
    display: grid;
    gap: var(--mrg-semantic-space-stack-xs);
  }
  .mrg-chart figcaption strong {
    font-size: var(--mrg-semantic-font-size-heading-small);
  }
  .mrg-chart figcaption span {
    max-inline-size: 70ch;
    color: var(--mrg-semantic-color-foreground-muted);
    line-height: var(--mrg-semantic-font-line-height-body);
  }
  .mrg-chart__plot {
    inline-size: 100%;
    block-size: 14rem;
    overflow: visible;
    color: var(--mrg-semantic-color-brand-action);
  }
  .mrg-chart__plot polyline {
    fill: none;
    stroke: currentColor;
    stroke-width: var(--mrg-semantic-border-width-emphasis);
  }
  .mrg-chart__plot circle {
    fill: var(--mrg-semantic-color-background-canvas);
    stroke: var(--mrg-semantic-color-brand-violet);
    stroke-width: var(--mrg-semantic-border-width-emphasis);
  }
  .mrg-chart__plot circle[data-active] {
    fill: var(--mrg-semantic-color-brand-living);
    stroke: var(--mrg-semantic-color-foreground-primary);
  }
  .mrg-chart__point-controls {
    display: flex;
    flex-wrap: wrap;
    gap: var(--mrg-semantic-space-inline-sm);
    margin: 0;
    padding: 0;
    list-style: none;
  }
  .mrg-chart__point-controls button {
    display: grid;
    gap: var(--mrg-semantic-space-stack-xs);
    min-block-size: var(--mrg-semantic-size-target-minimum);
    padding: var(--mrg-semantic-space-inset-sm);
    border: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-interactive);
    border-radius: var(--mrg-semantic-radius-control);
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-canvas);
    font: inherit;
    text-align: start;
  }
  .mrg-chart__point-controls button[aria-pressed="true"] {
    border-color: var(--mrg-semantic-color-selection-border);
    color: var(--mrg-semantic-color-selection-foreground);
    background: var(--mrg-semantic-color-selection-background);
  }
  .mrg-chart :is(button, summary):focus-visible {
    box-shadow: 0 0 0 var(--mrg-semantic-focus-width)
      var(--mrg-semantic-color-focus-contrast-background);
    outline: var(--mrg-semantic-focus-width) solid var(--mrg-semantic-color-focus-ring);
    outline-offset: var(--mrg-semantic-focus-offset);
  }
  .mrg-chart__table {
    overflow: auto;
  }
  .mrg-chart__table summary {
    min-block-size: var(--mrg-semantic-size-target-minimum);
    cursor: pointer;
    font-weight: var(--mrg-semantic-font-weight-label);
  }
  .mrg-chart table {
    inline-size: 100%;
    border-collapse: collapse;
  }
  .mrg-chart th,
  .mrg-chart td {
    padding: var(--mrg-semantic-space-inset-sm);
    border-block-start: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-default);
    text-align: start;
  }
  .mrg-chart__empty {
    padding-block: var(--mrg-semantic-space-stack-lg);
    color: var(--mrg-semantic-color-foreground-muted);
    text-align: center;
  }
  @media (pointer: coarse) {
    .mrg-chart__point-controls button,
    .mrg-chart__table summary {
      min-inline-size: var(--mrg-semantic-size-target-preferred);
      min-block-size: var(--mrg-semantic-size-target-preferred);
    }
  }
  @media (forced-colors: active) {
    .mrg-chart,
    .mrg-chart__point-controls button {
      border-color: CanvasText;
      color: CanvasText;
      background: Canvas;
    }
    .mrg-chart__plot {
      color: CanvasText;
    }
    .mrg-chart__plot circle,
    .mrg-chart__plot circle[data-active] {
      fill: Canvas;
      stroke: CanvasText;
    }
    .mrg-chart__point-controls button[aria-pressed="true"] {
      color: HighlightText;
      background: Highlight;
    }
    .mrg-chart :is(button, summary):focus-visible {
      box-shadow: none;
      outline-color: Highlight;
    }
  }
}

"use client";

import "./chart.css";

import { useId, useState, type HTMLAttributes, type ReactElement, type ReactNode } from "react";

export interface ChartPoint {
  /** Provides the stable point identifier used by optional active state. */
  readonly id: string;
  /** Presents the point’s category in controls and the table fallback. */
  readonly label: string;
  /** Supplies the finite numeric value represented by the plotted point. */
  readonly value: number;
}

export interface ChartProps extends Omit<HTMLAttributes<HTMLElement>, "children" | "onChange"> {
  /** Provides the visible chart title and accessible graphic name. */
  readonly name: string;
  /** Explains the chart’s measure or intended interpretation. */
  readonly description: string;
  /** Supplies ordered points for the plot and equivalent data table. */
  readonly points: readonly ChartPoint[];
  /** Labels the value column in the equivalent data table. */
  readonly valueLabel?: string;
  /** Formats values consistently in controls and the equivalent data table. */
  readonly formatValue?: (value: number, point: ChartPoint) => string;
  /** Keeps the equivalent table visible or inside a native disclosure. */
  readonly dataTableFallback?: "visible" | "disclosure";
  /** Adds pressable point controls; false removes their UI and pressed semantics. */
  readonly interactive?: boolean;
  /** Controls the active point when optional interaction is enabled. */
  readonly activePointId?: string | null;
  /** Sets the initial active point for uncontrolled interaction. */
  readonly defaultActivePointId?: string | null;
  /** Reports activated points without changing canonical point data. */
  readonly onActivePointChange?: (point: ChartPoint) => void;
  /** Replaces the default content shown when no points exist. */
  readonly emptyContent?: ReactNode;
}

function classes(...values: readonly (string | undefined | false)[]): string {
  return values.filter((value): value is string => Boolean(value)).join(" ");
}

export function Chart({
  name,
  description,
  points,
  valueLabel = "Value",
  formatValue = (value) => String(value),
  dataTableFallback = "disclosure",
  interactive = false,
  activePointId,
  defaultActivePointId = null,
  onActivePointChange,
  emptyContent = "No chart data",
  className,
  ...props
}: ChartProps): ReactElement {
  const descriptionId = useId();
  const nameId = useId();
  const [internalActive, setInternalActive] = useState<string | null>(defaultActivePointId);
  const active = activePointId === undefined ? internalActive : activePointId;
  const values = points.map((point) => point.value);
  const minimum = Math.min(...values, 0);
  const maximum = Math.max(...values, 1);
  const range = Math.max(1, maximum - minimum);
  const coordinates = points.map((point, index) => ({
    point,
    x: points.length <= 1 ? 50 : (index / (points.length - 1)) * 100,
    y: 92 - ((point.value - minimum) / range) * 84,
  }));
  const table = (
    <table>
      <caption>{name} data</caption>
      <thead>
        <tr>
          <th scope="col">Label</th>
          <th scope="col">{valueLabel}</th>
        </tr>
      </thead>
      <tbody>
        {points.map((point) => (
          <tr key={point.id}>
            <th scope="row">{point.label}</th>
            <td>{formatValue(point.value, point)}</td>
          </tr>
        ))}
      </tbody>
    </table>
  );
  return (
    <figure
      {...props}
      className={classes("mrg-chart", className)}
      data-slot="chart"
      data-interactive={interactive || undefined}
    >
      <figcaption>
        <strong id={nameId}>{name}</strong>
        <span id={descriptionId}>{description}</span>
      </figcaption>
      {points.length === 0 ? (
        <div className="mrg-chart__empty">{emptyContent}</div>
      ) : (
        <>
          <svg
            viewBox="0 0 100 100"
            role="img"
            aria-labelledby={`${nameId} ${descriptionId}`}
            className="mrg-chart__plot"
            preserveAspectRatio="none"
          >
            <polyline
              aria-hidden="true"
              points={coordinates.map(({ x, y }) => `${x},${y}`).join(" ")}
              vectorEffect="non-scaling-stroke"
            />
            {coordinates.map(({ point, x, y }) => (
              <circle
                key={point.id}
                aria-hidden="true"
                cx={x}
                cy={y}
                r="2"
                data-active={active === point.id || undefined}
                vectorEffect="non-scaling-stroke"
              />
            ))}
          </svg>
          {interactive ? (
            <ol aria-label={`${name} data points`} className="mrg-chart__point-controls">
              {points.map((point) => (
                <li key={point.id}>
                  <button
                    type="button"
                    aria-pressed={active === point.id}
                    onClick={() => {
                      if (activePointId === undefined) setInternalActive(point.id);
                      onActivePointChange?.(point);
                    }}
                  >
                    <span>{point.label}</span>
                    <strong>{formatValue(point.value, point)}</strong>
                  </button>
                </li>
              ))}
            </ol>
          ) : null}
          {dataTableFallback === "visible" ? (
            <div className="mrg-chart__table">{table}</div>
          ) : (
            <details className="mrg-chart__table">
              <summary>View chart data</summary>
              {table}
            </details>
          )}
        </>
      )}
    </figure>
  );
}
